package com.example.cms.project.change; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class ChangeRequestService { private final JdbcTemplate jdbc; public ChangeRequestService(JdbcTemplate jdbc){this.jdbc=jdbc;} public List<Map<String,Object>> list(String table){return jdbc.queryForList("select * from "+table+" order by id");} }
